    <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Aroon-Oszillator: Trend vs. Seitwärtsmarkt (Konzeptionell)</text>
    <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">Aroon-Oszillator (Up−Down) · illustratives Beispiel</text>
    <line x1="60" y1="70" x2="640" y2="70" stroke="#27272a" stroke-width="1"/>
    <line x1="60" y1="152" x2="640" y2="152" stroke="#3f3f46" stroke-width="1" stroke-dasharray="4,4"/>
    <line x1="60" y1="234" x2="640" y2="234" stroke="#52525b" stroke-width="1.2"/>
    <line x1="60" y1="316" x2="640" y2="316" stroke="#3f3f46" stroke-width="1" stroke-dasharray="4,4"/>
    <line x1="60" y1="398" x2="640" y2="398" stroke="#27272a" stroke-width="1"/>
